codeExample.code:
-- Delta Lake: compact and Z-order by two high-cardinality columns
OPTIMIZE analytics.events
WHERE event_date >= '2026-04-01'
ZORDER BY (user_id, event_type);

-- Iceberg equivalent: define sort order at table level
ALTER TABLE analytics.events
WRITE ORDERED BY user_id ASC NULLS LAST, event_type ASC NULLS LAST;

-- Then compact to apply the sort order:
CALL system.rewrite_data_files(
  table => 'analytics.events',
  strategy => 'sort',
  sort_order => 'user_id ASC, event_type ASC'
);
